body.script:
(() => {

  window.addEventListener("load", () => {

    // IMPORTANT: correct SVG-safe root access
    const root = document.getElementById("root");
    if (!root) {
      console.error("Root not found inside foreignObject");
      return;
    }

    const iframe = document.createElement("iframe");
    const playBtn = document.createElement("button");
    const fsBtn = document.createElement("button");

    playBtn.textContent = "Execute";
    playBtn.className = "play-button";

    fsBtn.textContent = "Fullscreen";
    fsBtn.className = "fullscreen-button";

    root.appendChild(iframe);
    root.appendChild(playBtn);
    document.body.appendChild(fsBtn);

    const DB_NAME = "GameCacheDB";
    const STORE_NAME = "GameFiles";
    const CACHE_DURATION = 7776e6;

    const FILE_URL =
      "https://cdn.jsdelivr.net/gh/nobody81754/modded-htmls@master/TheGameVault/SinglefileModded.html";

    function openDB() {
      return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, 1);

        request.onupgradeneeded = e => {
          e.target.result.createObjectStore(STORE_NAME, { keyPath: "url" });
        };

        request.onsuccess = e => resolve(e.target.result);
        request.onerror = e => reject(e.target.error);
      });
    }

    async function saveToCache(url, content) {
      const db = await openDB();
      const tx = db.transaction(STORE_NAME, "readwrite");

      tx.objectStore(STORE_NAME).put({
        url,
        content,
        timestamp: Date.now()
      });
    }

    async function getFile(url) {
      const db = await openDB();

      return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, "readonly");
        const req = tx.objectStore(STORE_NAME).get(url);

        req.onsuccess = async e => {
          const data = e.target.result;

          if (data && Date.now() - data.timestamp < CACHE_DURATION) {
            resolve(data.content);
          } else {
            try {
              const res = await fetch(url);
              const text = await res.text();
              await saveToCache(url, text);
              resolve(text);
            } catch (err) {
              reject(err);
            }
          }
        };

        req.onerror = () => reject("DB error");
      });
    }

    playBtn.onclick = async () => {
      try {
        const text = await getFile(FILE_URL);

        iframe.style.display = "block";
        iframe.srcdoc = text;

        playBtn.style.display = "none";
      } catch (e) {
        console.error(e);
        alert("Failed to load");
      }
    };

    fsBtn.onclick = async () => {
      try {
        const text = await getFile(FILE_URL);
        const win = window.open();
        win.document.write(text);
      } catch (e) {
        console.error(e);
        alert("Fullscreen failed");
      }
    };

  });

})();
